;/* CHROME 1.9.1 OPTIONS LIVE THEME FIX */
(()=>{
  const apply=(v)=>{
    let theme=String(v||'auto');
    if(theme==='auto') theme=matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light';
    document.documentElement.setAttribute('data-theme',theme);
    document.body?.setAttribute('data-theme',theme);
  };
  document.addEventListener('change',e=>{
    const t=e.target;
    if(t?.name==='theme_mode'&&t.checked) apply(t.value);
  });
  chrome.storage.onChanged.addListener((c,a)=>{if(a==='local'&&c.theme_mode)apply(c.theme_mode.newValue)});
  chrome.storage.local.get(['theme_mode']).then(x=>apply(x.theme_mode||'auto')).catch(()=>{});
})();
